/**
 * Global Error Handler Middleware
 *
 * Catches all errors and converts them to a consistent API response format.
 * Follows the error response format from API_CONTRACTS.md.
 *
 * @module core/middleware/error
 */

import { Request, Response, NextFunction, ErrorRequestHandler } from 'express';
import { ZodError } from 'zod';
import { AppException, isAppException, ValidationError } from '@/core/exceptions/app.exception';
import { env, isDevelopment } from '@/config/env';

// -----------------------------------------------------------------------------
// Type Definitions
// -----------------------------------------------------------------------------

/**
 * Standardized API error response format
 * Follows API_CONTRACTS.md specification
 */
export interface ErrorResponse {
  success: false;
  error: {
    /** Machine-readable error code */
    code: string;
    /** Human-readable error message */
    message: string;
    /** Additional error details (validation errors, etc.) */
    details?: unknown;
    /** Request ID for support reference */
    requestId: string;
    /** Error occurrence timestamp */
    timestamp: string;
    /** Stack trace (development only) */
    stack?: string;
  };
}

/**
 * Request with optional request ID
 */
interface RequestWithId extends Request {
  /** Request ID for correlation */
  id?: string;
}

// -----------------------------------------------------------------------------
// Error Detection Helpers
// -----------------------------------------------------------------------------

/**
 * Checks if an error is a Zod validation error
 */
function isZodError(error: unknown): error is ZodError {
  return error instanceof ZodError;
}

/**
 * Checks if an error is a Prisma error
 * Prisma errors have specific codes like P2000, P2001, etc.
 */
function isPrismaError(error: unknown): error is Error & { code: string; meta?: Record<string, unknown> } {
  return (
    error instanceof Error &&
    'code' in error &&
    typeof (error as { code: unknown }).code === 'string' &&
    (error as { code: string }).code.startsWith('P')
  );
}

/**
 * Checks if an error is a JSON parsing error
 */
function isJsonParseError(error: unknown): boolean {
  return error instanceof SyntaxError && 'body' in error;
}

// -----------------------------------------------------------------------------
// Error Conversion Functions
// -----------------------------------------------------------------------------

/**
 * Converts Zod validation errors to our ValidationError format
 */
function convertZodErrors(zodError: ZodError): ValidationError[] {
  return zodError.errors.map((err) => ({
    field: err.path.join('.'),
    message: err.message,
    rule: err.code,
  }));
}

/**
 * Converts Prisma errors to AppException
 */
function convertPrismaError(error: Error & { code: string; meta?: Record<string, unknown> }): AppException {
  const code = error.code;
  const meta = error.meta;

  switch (code) {
    // Unique constraint violation
    case 'P2002': {
      const target = (meta?.target as string[])?.join(', ') || 'field';
      return AppException.alreadyExists('Resource', target);
    }

    // Foreign key constraint violation
    case 'P2003': {
      const field = meta?.field_name as string;
      return AppException.invalidInput(`Invalid reference: ${field || 'related record not found'}`, field);
    }

    // Record not found
    case 'P2001':
    case 'P2025': {
      return AppException.notFound('Resource');
    }

    // Record too long
    case 'P2000': {
      const column = meta?.column_name as string;
      return AppException.invalidInput(`Value too long for field: ${column || 'unknown'}`, column);
    }

    // Null constraint violation
    case 'P2011': {
      const constraint = meta?.constraint as string;
      return AppException.invalidInput(`Required field missing: ${constraint || 'unknown'}`);
    }

    // Connection/timeout errors
    case 'P2024': {
      return AppException.serviceUnavailable('database');
    }

    // Default database error
    default: {
      return AppException.databaseError(code);
    }
  }
}

/**
 * Generates a unique request ID
 */
function generateRequestId(): string {
  const timestamp = Date.now().toString(36);
  const random = Math.random().toString(36).substring(2, 8);
  return `req_${timestamp}${random}`;
}

// -----------------------------------------------------------------------------
// Error Handler Middleware
// -----------------------------------------------------------------------------

/**
 * Global error handler middleware.
 * Catches all errors thrown in the request pipeline and returns a consistent error response.
 *
 * Features:
 * - Converts AppException to API error format
 * - Handles Zod validation errors
 * - Handles Prisma database errors
 * - Handles JSON parsing errors
 * - Generates request IDs for tracking
 * - Hides stack traces in production
 *
 * @example
 * ```typescript
 * import express from 'express';
 * import { errorHandler } from '@/core/middleware/error.middleware';
 *
 * const app = express();
 *
 * // ... routes ...
 *
 * // Error handler must be last middleware
 * app.use(errorHandler);
 * ```
 */
export const errorHandler: ErrorRequestHandler = (
  err: unknown,
  req: Request,
  res: Response,
  _next: NextFunction
): void => {
  // Get or generate request ID
  const reqWithId = req as RequestWithId;
  const requestId = reqWithId.id || req.get('X-Request-ID') || generateRequestId();

  // Timestamp for error
  const timestamp = new Date().toISOString();

  // Convert error to AppException
  let exception: AppException;

  if (isAppException(err)) {
    // Already an AppException
    exception = err;
  } else if (isZodError(err)) {
    // Zod validation error
    const validationErrors = convertZodErrors(err);
    exception = AppException.validation(validationErrors);
  } else if (isPrismaError(err)) {
    // Prisma database error
    exception = convertPrismaError(err);
  } else if (isJsonParseError(err)) {
    // JSON parsing error
    exception = new AppException('INVALID_JSON', 400, {
      message: 'Malformed JSON in request body',
    });
  } else if (err instanceof Error) {
    // Generic Error
    exception = AppException.internal(isDevelopment() ? err.message : undefined);
  } else {
    // Unknown error type
    exception = AppException.internal();
  }

  // Get error details
  const errorDetails = exception.details || {};
  const message = (errorDetails as { message?: string }).message || exception.code;

  // Build error response
  const errorResponse: ErrorResponse = {
    success: false,
    error: {
      code: exception.code,
      message: message,
      requestId,
      timestamp,
    },
  };

  // Add details if present (e.g., validation errors)
  if (exception.details) {
    // Extract validation errors array if present
    const details = exception.details as { errors?: ValidationError[]; [key: string]: unknown };
    if (details.errors) {
      errorResponse.error.details = details.errors;
    } else if (Object.keys(details).length > 1 || !details.message) {
      // Include details if there's more than just a message
      const { message: _msg, ...rest } = details;
      if (Object.keys(rest).length > 0) {
        errorResponse.error.details = rest;
      }
    }
  }

  // Include stack trace in development
  if (isDevelopment() && err instanceof Error) {
    errorResponse.error.stack = err.stack;
  }

  // Log error (in development or for server errors)
  if (isDevelopment() || exception.statusCode >= 500) {
    const logData = {
      requestId,
      method: req.method,
      path: req.path,
      statusCode: exception.statusCode,
      code: exception.code,
      message,
      ...(err instanceof Error && { stack: err.stack }),
    };

    if (exception.statusCode >= 500) {
      console.error('[ERROR]', JSON.stringify(logData, null, 2));
    } else if (isDevelopment()) {
      console.warn('[WARN]', JSON.stringify(logData, null, 2));
    }
  }

  // Send response
  res.status(exception.statusCode).json(errorResponse);
};

// -----------------------------------------------------------------------------
// 404 Not Found Handler
// -----------------------------------------------------------------------------

/**
 * 404 Not Found handler middleware.
 * Use this as the last route handler to catch unmatched routes.
 *
 * @example
 * ```typescript
 * import express from 'express';
 * import { notFoundHandler, errorHandler } from '@/core/middleware/error.middleware';
 *
 * const app = express();
 *
 * // ... routes ...
 *
 * // 404 handler for unmatched routes
 * app.use(notFoundHandler);
 *
 * // Error handler must be last
 * app.use(errorHandler);
 * ```
 */
export function notFoundHandler(req: Request, _res: Response, next: NextFunction): void {
  next(
    new AppException('ROUTE_NOT_FOUND', 404, {
      message: `Cannot ${req.method} ${req.path}`,
      path: req.path,
      method: req.method,
    })
  );
}

// -----------------------------------------------------------------------------
// Async Handler Wrapper
// -----------------------------------------------------------------------------

/**
 * Wraps async route handlers to catch errors and pass them to error middleware.
 * Eliminates the need for try-catch in every route handler.
 *
 * @param fn - Async route handler function
 * @returns Express request handler
 *
 * @example
 * ```typescript
 * import { asyncHandler } from '@/core/middleware/error.middleware';
 *
 * router.get('/menus', asyncHandler(async (req, res) => {
 *   const menus = await menuService.findAll();
 *   res.json({ success: true, data: menus });
 * }));
 * ```
 */
export function asyncHandler(
  fn: (req: Request, res: Response, next: NextFunction) => Promise<unknown>
): (req: Request, res: Response, next: NextFunction) => void {
  return (req: Request, res: Response, next: NextFunction): void => {
    Promise.resolve(fn(req, res, next)).catch(next);
  };
}

// -----------------------------------------------------------------------------
// Error Boundary for Critical Sections
// -----------------------------------------------------------------------------

/**
 * Wraps a function to catch errors and convert them to AppException.
 * Useful for service layer error handling.
 *
 * @param fn - Function to wrap
 * @param errorMessage - Optional error message for failures
 * @returns Result of the function
 *
 * @example
 * ```typescript
 * const result = await withErrorBoundary(
 *   () => prisma.menu.create({ data }),
 *   'Failed to create menu'
 * );
 * ```
 */
export async function withErrorBoundary<T>(
  fn: () => Promise<T>,
  errorMessage?: string
): Promise<T> {
  try {
    return await fn();
  } catch (error) {
    if (isAppException(error)) {
      throw error;
    }

    if (isPrismaError(error)) {
      throw convertPrismaError(error);
    }

    if (error instanceof Error) {
      throw AppException.internal(errorMessage || error.message);
    }

    throw AppException.internal(errorMessage);
  }
}
